cremoves(ll demask, int pos, char ch){
  if(ch=='.' || ch=='D'){
    demask=demask&(~(1<<pos));
  }
  else{
    demask=demask|(1l<<pos);
  }
  return demask;
}
bool solve(vector<pair<ll,int>> pipes,ll demask){
  int total=n,p=theans_tube[n-1];
  for(int i=n-2;i>=0;i--){
    ll pipe=pipes[i].first;
    int pos=pipes[i].second;
    demask=removes(demask,pos,'D');
    total--;
    if(demask==0){
      for(int j=i;j>pos;j--){
        demask=removes(demask,j,'D');
        total--;
      }
      break;
    }
  }
  //cout<<"demask:");
  //print(demask);
  //cout<<',';
  return demask==1?true:false;
}
long long count(vector<pair<ll,int>> pipes){
    ll demask=res=demask_tube[n-1];
  res=0;
  for(int i=1;i<(1ll<<n);i++){
    res+=solve(pipes,i);
  }
  //cout<<res;
  return res;
}
signed main(){
  cin>>n;
  vector<pair<ll,int>> pipes;
  for(int i=0;i<n-1;i++){
    vector<ll> pr;
    int v1,c;
    for(int j=0;j<n;j++){
      cin>>v;
      if(v=='1'){
        v1=j;
          pr.push_back(v);
          c=i;
          break;
        }
      }
    sort(pr.begin(),pr.end());
    pipes.push_back({pr,c});
  }
  //count(pipes);
}
}

