import re
from dataclasses import dataclass
from typing import Dict


class Book:
    """Class Book contains all possible books in indian bookshelves"""

    __book_id_dict: Dict[int, str]
    __queries_booklist_id_dict: Dict[str: str]

    _id = 1

    def __init__(self, data):
        self.data = data

    def data_dict(self):
        return self.data

    @classmethod
    def create_book_list(cls):
        cls.__book_id_dict = {}

        with open("book.txt", "r") as data:
            for i in data:
                data = {}
                i = i.replace("\n", "").replace("\'", "").replace("(", "").replace(")", "").split(" - ")
                id = cls._id
                cls._id += 1
                data["title"] = i[1]
                data["author"] = i[2]
                data["language"] = i[3]
                data["publication_year"] = i[4]
                data["genre"] = i[5]
                cls.__book_id_dict[id] = data
                i = "/n"

        data = list(cls.__book_id_dict.items())
        data.sort(key=lambda tup: (tup[0], tup[0]))

        cls.__book_id_dict = {k: v for k, v in data}

    def __subself__(self, other):
        res = self.data["title"] in other.data["title"]
        return res

    def __mul__(self, other):
        res = self.data["author"].strip(", ").lower() in other.data["author"].strip(", ").lower()
        return res

    def __gt__(self, other):
        res = self.data["genre"].lower() in other.data["genre"].lower()
        return res

    def __lt__(self, other):
        res = other.data["genre"].lower() in self.data["genre"].lower()
        return res

    static_id = 1

    def search_book(self, book_id):
        book_id = int(book_id)
        return self.__book_id_dict.get(book_id)

    def search_book_id(self, book_list):
        book_list = list(book_list.items())
        book_list.sort(key=lambda x: Book.static_id + x[1]["title"].lower(), reverse=True)
        book_id_dict = {book_list[i][1]['title']: book_list[i][0] for i in range(len(book_list))}
        return book_id_dict


