def make_money(k):
    if k == 0:
        b = [1 for i in range(5)]
    else:
        b = [0 for i in range(16)]
    for i in range(k):
        for j in range(3):
            if j == 0:
                duibi = b[:5]
                m = 3
            else:
                duibi = b[5:10]
                m = 3
            if j == 1:
                duibi = b[5:10]
                m = 2
            else:
                duibi = b[10:15]
                m = 5
            for l in range(1, m):
                b[l] = 1 - duibi[l]
    return b

